mapper.select:
	SELECT total_point
        FROM students
        WHERE student_id = #{studentId}

	 SELECT total_coupon
        FROM students
        WHERE student_id = #{studentId}

	SELECT name
        FROM stocks
        WHERE stock_id = #{stockId}

	SELECT COALESCE(SUM(CASE WHEN content = '매수' THEN amount ELSE -amount END), 0) AS amount
        FROM orders
        WHERE student_id = #{studentId}
          AND stock_id = #{stockId}
          AND state = #{state}

	SELECT COALESCE((SUM(price * amount) / SUM(amount)), 0) AS average
        FROM orders
        WHERE student_id = #{studentId}
          AND stock_id = #{stockId}
          AND state = #{state}
          AND content = #{content}

SELECT COALESCE(SUM(price * amount), 0) AS purchasePrice
        FROM orders
        WHERE student_id = #{studentId}
          AND stock_id = #{stockId}
          AND state = #{state}
          AND content = #{content}

SELECT COALESCE(
           (
               (
                   SUM(CASE WHEN content = '매수' THEN amount ELSE -amount END)
                   *
                   (
                       SELECT COALESCE(
                           (
                                   SELECT price
                                   FROM orders
                                   WHERE stock_id = #{stockId}
                                     AND state = '체결'
                                   ORDER BY created_date DESC
                                   LIMIT 1
                           ),
                           st.publication_price
                       )
                       FROM stocks st
                       WHERE st.stock_id = o.stock_id
                   )
               )
               -
               SUM(CASE WHEN content = '매수' THEN price * amount ELSE 0 END)
           ),
           0
       ) AS profit
       FROM orders o
       WHERE o.student_id = #{studentId}
         AND o.stock_id = #{stockId}
         AND o.state = #{state}
       GROUP BY stock_id

	SELECT DISTINCT stock_id
        FROM orders
        WHERE student_id = #{studentId}
          AND state = #{state}
